SELECT crafter_name
FROM crafters
WHERE rating > 4.5;

SELECT COUNT(*) as session_count
FROM crafting_sessions
WHERE crafter_id = 1;

SELECT crafted_item_id 
FROM crafted_items 
ORDER BY crafted_item_id;

SELECT crafter_name
FROM crafters
WHERE experience_level = (SELECT MAX(experience_level) FROM crafters);

SELECT crafter_name
FROM crafters
WHERE rating = (SELECT MAX(rating) FROM crafters);

SELECT COUNT(*) AS active_recipe_count
FROM crafting_recipes
WHERE is_active = 1;
